class DSU:
    def __init__(self, n):
        self.parent = list(range(n))
        self.num_components = n

    def find(self, i):
        if self.parent[i] == i:
            return i
        self.parent[i] = self.find(self.parent[i])
        return self.parent[i]

    def union(self, i, j):
        root_i = self.find(i)
        root_j = self.find(j)
        if root_i != root_j:
            self.parent[root_j] = root_i
            self.num_components -= 1
            return True
        return False

def boruvka(n_vertices, edges):
    dsu = DSU(n_vertices)
    mst_weight = 0
    mst_edges = []

    while dsu.num_components > 1:
        cheapest_edges_for_roots = {}

        for u, v, weight in edges:
            root_u = dsu.find(u)
            root_v = dsu.find(v)

            if root_u != root_v:
                if root_u not in cheapest_edges_for_roots or weight < cheapest_edges_for_roots[root_u][0]:
                    cheapest_edges_for_roots[root_u] = (weight, u, v)

                if root_v not in cheapest_edges_for_roots or weight < cheapest_edges_for_roots[root_v][0]:
                    cheapest_edges_for_roots[root_v] = (weight, u, v)

        if not cheapest_edges_for_roots:
            break

        edges_to_add_this_phase = set()
        for edge_info in cheapest_edges_for_roots.values():
            edges_to_add_this_phase.add(edge_info)

        for weight, u, v in edges_to_add_this_phase:
            if dsu.union(u, v):
                mst_weight += weight
                mst_edges.append((u, v, weight))

    if dsu.num_components == 1:
        return mst_weight, mst_edges
    else:
        return -1, []
